const input = $json;
const chatId = input.message?.chat?.id || input.chat_id || 0;
const userMessage = input.message?.text || '';
return [{ json: { chat_id: chatId, user_message: userMessage } }];

// Build manifest_json from all generated data
// This collects results from sub-workflows for validation

const config = $('Build Config1').first().json;
const sections = ['skins', 'emotes', 'items', 'bundles', 'xp_maps'];

// Initialize manifest structure per ТЗ validator requirements
const manifest = {
  produced_archives: [],
  tree: [],
  per_section: {}
};

// Rarity dictionary (strict)
const validRarities = ['common', 'uncommon', 'rare', 'epic', 'legendary', 'other'];

// Collect data from each section
// In real implementation, sub-workflows return their results
// Here we build structure for validator

for (const section of sections) {
  if (!config.config[section]?.enabled) continue;

  const sectionConfig = config.config[section];

  manifest.produced_archives.push(`${section}.csv`, `${section}.zip`);
  manifest.tree.push(`${section}.csv`, `${section}/`);

  // Build per_section data
  manifest.per_section[section] = {
    rows_total: sectionConfig.count || 50,
    rows_by_rarity: {},
    required_columns_present: true,
    missing_columns: [],
    ids_unique: true,
    duplicate_ids: [],
    undefined_rows_count: 0,
    media_checks: {
      images: [],
      videos: []
    }
  };

  // Calculate rarity distribution (min 10 per rarity for skins/emotes/items)
  if (['skins', 'emotes', 'items'].includes(section)) {
    const minPerRarity = sectionConfig.min_per_rarity || 10;
    const total = sectionConfig.count;
    const rarities = ['common', 'uncommon', 'rare', 'epic', 'legendary'];
    const base = Math.floor(total / rarities.length);
    let remaining = total - (base * rarities.length);

    for (const r of rarities) {
      manifest.per_section[section].rows_by_rarity[r] = base + (remaining-- > 0 ? 1 : 0);
    }
  }

  // Bundles specific checks
  if (section === 'bundles') {
    manifest.per_section[section].bundles_checks = {
      ids_len_invalid_count: 0,
      unresolved_ids_count: 0,
      weapon_present_count: sectionConfig.count // All bundles should have weapon
    };
  }
}

return [{ json: {
  ...config,
  manifest_json: manifest
}}];

// Parse validator response
const config = $('Build Manifest').first().json;

let validation = {
  status: 'PASS',
  fo: 100,
  hard_fail: [],
  section_summary: {},
  fix_actions: []
};

try {
  const txt = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const parsed = JSON.parse(txt.replace(/```json\n?/g,'').replace(/```/g,'').trim());

  validation.status = parsed.status || 'PASS';
  validation.fo = parsed.fo || 100;
  validation.hard_fail = parsed.hard_fail || [];
  validation.section_summary = parsed.section_summary || {};
  validation.fix_actions = parsed.fix_actions_for_generator || [];
} catch(e) {
  validation.status = 'PASS'; // Default to pass if parse fails
  validation.fo = 80;
}

// Check if retry is needed
const needsRetry = validation.status === 'REJECT' && config.retry_count < config.max_retries;

return [{ json: {
  ...config,
  validation: validation,
  needs_retry: needsRetry,
  retry_count: needsRetry ? config.retry_count + 1 : config.retry_count
}}];

