    if (parsed.segment) config.segment = parsed.segment;

    if (parsed.sounds) config.sounds = mergeDeep({ ...config.sounds }, parsed.sounds);
    if (parsed.courses) config.courses = mergeDeep({ ...config.courses }, parsed.courses);
    if (parsed.games) config.games = mergeDeep({ ...config.games }, parsed.games);
